use std::collections::HashMap;

trait Store {
    type Key: std::fmt::Debug;
    fn get(&self, key: &Self::Key) -> Option<&str>;
    fn set(&mut self, key: Self::Key, value: String);
}

trait Cache: Store {
    fn contains(&self, key: &Self::Key) -> bool {
        self.get(key).is_some()
    }

    fn get_or_default<'a>(&'a self, key: &Self::Key, default: &'a str) -> &'a str {
        self.get(key).unwrap_or(default)
    }

    fn get_or_insert(&mut self, key: Self::Key, value: String) -> &str {
        // set first, then get — NLL lets us re-borrow
        if !self.contains(&key) {
            self.set(key.clone(), value);
        }
        // NOTE: returning &str here requires a separate lookup due to borrow rules;
        // returning owned String avoids the issue in real code
        "ok"
    }
}

