impl Store for MapStore {
    type Key = String;
    fn get(&self, key: &String) -> Option<&str> {
        self.inner.get(key).map(String::as_str)
    }
    fn set(&mut self, key: String, value: String) {
        self.inner.insert(key, value);
    }
}

impl Cache for MapStore {}

fn main() {
    let mut store = MapStore { inner: HashMap::new() };
    store.set(String::from("name"), String::from("Alice"));
    println!("has name: {}", store.contains(&String::from("name")));
    println!("age: {}", store.get_or_default(&String::from("age"), "unknown"));
}

